async function enterItem(item: CommandItem) {
  const result = await item.action()
  if (!result) {
    overrideItems.value = undefined
    search.value = ''
    show.value = false
  }
  else {
    overrideItems.value = result
    search.value = ''
  }
}

async function showPopup() {
  try {
    const [source, modified] = await rpc.enableTimeline(true)
    if (!await Dialog.start(source, modified))
      return
    await rpc.enableTimeline(false)
  }
  catch {
    devtoolsUiShowNotification({
      message: 'Failed to enable timeline automatically. Check the terminal for more details.',
      icon: 'i-carbon-warning',
      classes: 'text-red',
    })
  }
}

export async function resolveCollection(
  nuxt: Nuxt,
  collection: string | IconifyJSON | CustomCollection | RemoteCollection,
): Promise<string | IconifyJSON | RemoteCollection> {
  if (typeof collection === 'string')
    return collection
  // Custom collection
  if ('dir' in collection) {
    return await loadCustomCollection(collection, nuxt)
  }
  return collection
}

export function tryRequireModule<T = unknown> (id: string, opts?: ImportModuleOptions): T | undefined {
  try {
    // eslint-disable-next-line @typescript-eslint/no-deprecated
    return requireModule<T>(id, opts)
  } catch {
    // intentionally empty as this is a `try-` function
  }
}

export function getDirectory (p: string): string {
  try {
    // we need to target directories instead of module file paths themselves
    // /home/user/project/node_modules/module/index.js -> /home/user/project/node_modules/module
    return isAbsolute(p) && lstatSync(p).isFile() ? dirname(p) : p
  } catch {
    // maybe the path is absolute but does not exist, allow this to bubble up
  }
  return p
}

function sortTsPaths (paths: Record<string, string[]>) {
  for (const pathKey in paths) {
    if (pathKey.startsWith('#build')) {
      const pathValue = paths[pathKey]!
      // Delete & Reassign to ensure key is inserted at the end of object.
      delete paths[pathKey]
      paths[pathKey] = pathValue
    }
  }
}

function returnIslandResponse (event: H3Event, response: Partial<RenderResponse>) {
  for (const header in response.headers || {}) {
    event.res.headers.set(header, response.headers![header]!)
  }
  if (response.status) {
    event.res.status = response.status
  }
  if (response.statusText) {
    event.res.statusText = response.statusText
  }
  return response.body
}

function returnResponse (event: H3Event, response: Partial<RenderResponse>) {
  for (const header in response.headers || {}) {
    event.res.headers.set(header, response.headers![header]!)
  }
  if (response.status) {
    event.res.status = response.status
  }
  if (response.statusText) {
    event.res.statusText = response.statusText
  }

  return response.body
}

export function useAppConfig (event?: H3Event): AppConfig {
  // Backwards compatibility with ambient context
  if (!event) {
    return _sharedAppConfig
  }
  event.context.nuxt ||= {}
  // Reuse cached app config from event context
  if (event.context.nuxt.appConfig) {
    return event.context.nuxt.appConfig
  }
  // Prepare app config for event context
  const appConfig = klona(_inlineAppConfig)
  event.context.nuxt.appConfig = appConfig
  return appConfig
}

export function set<T> (target: any, key: string | number | symbol, val: T): T {
  if (Array.isArray(target)) {
    target.length = Math.max(target.length, key as number)
    target.splice(key as number, 1, val)
    return val
  }
  target[key] = val
  return val
}

function invokeAppErrorHandler (err, target, info) {
  const errorHandler = nuxtApp.vueApp.config.errorHandler
  if (errorHandler && !errorHandler.__nuxt_default) {
    try {
      errorHandler(err, target, info)
    } catch (handlerError) {
      console.error('[nuxt] Error in `app.config.errorHandler`', handlerError)
    }
  }
}

function createHash (_handler: AsyncDataHandler<unknown>, options: Partial<Record<keyof AsyncDataOptions<any>, unknown>>) {
  return {
    handler: hash(_handler),
    transform: options.transform ? hash(options.transform) : undefined,
    pick: options.pick ? hash(options.pick) : undefined,
    getCachedData: options.getCachedData ? hash(options.getCachedData) : undefined,
  }
}

async function writeCache (cwd: string, sources: string | string[], cacheFile: string) {
  const fileEntries = await readFilesRecursive(sources, {
    patterns: ['**/*', '!analyze/**'],
    cwd,
  })
  const tarData = createTar(fileEntries)
  await mkdir(dirname(cacheFile), { recursive: true })
  await writeFile(cacheFile, tarData)
}

async function checkAndWarnAboutConfigFileExistence (options: CheckAndWarnAboutConfigFileExistenceOptions) {
  const { fileName, extensions, createWarningMessage } = options

  const configFile = await findPath(fileName, { extensions }).catch(() => null)
  if (configFile) {
    return createWarningMessage(basename(configFile))
  }
}

function clientDevtool (ctx: WebpackConfigContext) {
  if (!ctx.nuxt.options.sourcemap.client) {
    ctx.config.devtool = false
    return
  }

  const prefix = ctx.nuxt.options.sourcemap.client === 'hidden' ? 'hidden-' : ''

  if (!ctx.isDev) {
    ctx.config.devtool = prefix + 'source-map'
    return
  }

  ctx.config.devtool = prefix + 'eval-cheap-module-source-map'
}

async function createPostcssLoadersRule (ctx: WebpackConfigContext) {
  if (!ctx.options.postcss) { return }

  const config = await getPostcssConfig(ctx.nuxt)

  if (!config) {
    return
  }

  return {
    loader: 'postcss-loader',
    options: config,
  }
}

async function main () {
  const workspace = await loadWorkspace(process.cwd())

  const newVersion = process.argv[2]
  if (!newVersion) {
    throw new Error('Please provide version!')
  }

  for (const pkg of workspace.packages.filter(p => !p.data.private)) {
    workspace.setVersion(pkg.data.name, newVersion!)
  }

  await workspace.save()
}

function normalizeFetchResponse(response: Response) {
  if (!response.headers.has('set-cookie')) {
    return response
  }
  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers: normalizeCookieHeaders(response.headers),
  })
}

async handler({ path, headings }) {
  let content
  try {
    content = await $fetch<string>(`/raw${path}.md`)
  } catch {
    throw createError({ statusCode: 404, message: `Documentation page not found at path: ${path}` })
  }

  if (headings && headings.length > 0) {
    content = extractSections(content, headings)
  }

  return content
}

function scrollToBottom(smooth: boolean = true) {
  if (!parent.value) {
    return
  }

  if (smooth) {
    parent.value.scrollTo({ top: parent.value.scrollHeight, behavior: 'smooth' })
  } else {
    parent.value.scrollTop = parent.value.scrollHeight
  }
}

async function validateNestedForm(form: { validate: typeof _validate, name?: string }, opts: ValidateOpts<boolean, boolean>) {
  try {
    const result = await form.validate({ ...opts, silent: false })
    return { name: form.name, output: result }
  } catch (error: unknown) {
    if (!(error instanceof FormValidationException)) throw error
    return { name: form.name, error }
  }
}

export function getNestedValue<T extends object, K extends string>(obj: T, key: K): any {
  const parts = key.split('.')
  let current: any = obj

  for (const part of parts) {
    if (current && typeof current === 'object' && part in current) {
      current = current[part as keyof typeof current]
    } else {
      return undefined // Key not found
    }
  }
  return current
}

function createTextComponent(name: string) {
  return (state: State, node: Parents) => {
    const result = {
      type: mdastTextComponentType,
      name,
      attributes: node.properties,
      children: state.all(node),
    }

    state.patch(node, result as Nodes)

    return result
  }
}

function getPreferredEncoding(event: H3Event): 'gzip' | 'deflate' | null {
  const acceptEncoding = getRequestHeader(event, 'accept-encoding') || ''
  if (acceptEncoding.includes('gzip'))
    return 'gzip'
  if (acceptEncoding.includes('deflate'))
    return 'deflate'
  return null
}

